changeSet.sql:
CREATE TABLE IF NOT EXISTS user_event_quota
(
    id              SERIAL PRIMARY KEY,
    user_id         INTEGER NOT NULL UNIQUE,
    event_count     BIGINT NOT NULL DEFAULT 0,
    period_start    TIMESTAMPTZ NOT NULL,
    updated_at      TIMESTAMPTZ NOT NULL DEFAULT (CURRENT_TIMESTAMP AT TIME ZONE 'UTC'),
    FOREIGN KEY (user_id) REFERENCES "user"(id) ON DELETE CASCADE
);

CREATE INDEX idx_user_event_quota_user ON user_event_quota(user_id);
CREATE INDEX idx_user_event_quota_period ON user_event_quota(period_start);

COMMENT ON TABLE user_event_quota IS 'Tracks monthly event usage per user with 1000 event limit';
COMMENT ON COLUMN user_event_quota.id IS 'Unique identifier for the quota record';
COMMENT ON COLUMN user_event_quota.user_id IS 'User this quota record belongs to (one per user)';
COMMENT ON COLUMN user_event_quota.event_count IS 'Number of events sent in current period';
COMMENT ON COLUMN user_event_quota.period_start IS 'Start of current billing period (first of month)';
COMMENT ON COLUMN user_event_quota.updated_at IS 'Last time quota was updated';
COMMENT ON INDEX idx_user_event_quota_user IS 'Index for fast user quota lookups';
COMMENT ON INDEX idx_user_event_quota_period IS 'Index for period-based queries';
